import torch
import torch.distributed as dist

class CopyWithAllReduceGrad(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input):
        return input.clone()

    @staticmethod
    def backward(ctx, grad_output):
        grad_input = grad_output.clone()
        dist.all_reduce(grad_input)
        return grad_input

import torch
import torch.nn as nn
import torch.nn.functional as F
import torch.distributed as dist

class CopyToModelParallelRegion(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input):
        return input

    @staticmethod
    def backward(ctx, grad_output):
        if not dist.is_initialized():
            return grad_output
        world_size = dist.get_world_size()
        if world_size == 1:
            return grad_output
        grad_input = grad_output.clone()
        dist.all_reduce(grad_input)
        return grad_input


class GatherFromModelParallelRegion(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input):
        if not dist.is_initialized():
            return input
        world_size = dist.get_world_size()
        if world_size == 1:
            return input

        input = input.contiguous()
        last_dim = input.dim() - 1
        tensor_list = [torch.empty_like(input) for _ in range(world_size)]
        tensor_list[dist.get_rank()] = input
        dist.all_gather(tensor_list, input)
        output = torch.cat(tensor_list, dim=last_dim)
        return output

    @staticmethod
    def backward(ctx, grad_output):
        if not dist.is_initialized():
            return grad_output
        world_size = dist.get_world_size()
        if world_size == 1:
            return grad_output

        last_dim = grad_output.dim() - 1
        rank = dist.get_rank()
        chunk_size = grad_output.shape[last_dim] // world_size
        grad_input = grad_output.narrow(last_dim, rank * chunk_size, chunk_size).contiguous()
        return grad_input


class ReduceFromModelParallelRegion(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input):
        if not dist.is_initialized():
            return input
        world_size = dist.get_world_size()
        if world_size == 1:
            return input

        output = input.clone()
        dist.all_reduce(output)
        return output

    @staticmethod
    def backward(ctx, grad_output):
        return grad_output


