        last_dim = input.dim() - 1
        rank = dist.get_rank()
        chunk_size = input.shape[last_dim] // world_size
        output = input.narrow(last_dim, rank * chunk_size, chunk_size).contiguous()
        return output

    @staticmethod
    def backward(ctx, grad_output):
        if not dist.is_initialized():
            return grad_output
        world_size = dist.get_world_size()
        if world_size == 1:
            return grad_output

        grad_output = grad_output.contiguous()
        last_dim = grad_output.dim() - 1
        tensor_list = [torch.empty_like(grad_output) for _ in range(world_size)]
        tensor_list[dist.get_rank()] = grad_output
        dist.all_gather(tensor_list, grad_output)
        grad_input = torch.cat(tensor_list, dim=last_dim)
        return grad_input


class ColumnParallelLinear(torch.nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features

        world_size = dist.get_world_size() if dist.is_initialized() else 1
        rank = dist.get_rank() if dist.is_initialized() else 0

        assert out_features % world_size == 0, "out_features must be divisible by world_size"
        self.out_features_per_partition = out_features // world_size

        # master_weight is of shape (out_features, in_features)
        # partition along out_features (dim 0)
        weight_partition = master_weight[
            rank * self.out_features_per_partition : (rank + 1) * self.out_features_per_partition, 
            :
        ].clone().detach()
        self.weight = nn.Parameter(weight_partition)

        if bias:
            self.bias = nn.Parameter(torch.zeros(self.out_features_per_partition))
        else:
            self.register_parameter('bias', None)

    def forward(self, x):
        # Ensure gradients to x are all_reduced
        x_parallel = CopyToModelParallelRegion.apply(x)

        # Local linear
        out_parallel = F.linear(x_parallel, self.weight, self.bias)

        # Gather output
        out = GatherFromModelParallelRegion.apply(out_parallel)
        return out


