        # Local linear without bias
        out_parallel = F.linear(x_parallel, self.weight, None)

        # Reduce over model parallel region
        out = ReduceFromModelParallelRegion.apply(out_parallel)

        # Add bias
        if self.bias is not None:
            out = out + self.bias

